var doc = Rhino.RhinoDoc.ActiveDoc;
var xform = Rhino.Geometry.Transform.Scale(Rhino.Geometry.Point3d.Origin, 2.0);
int scaled = 0;
foreach (var obj in doc.Objects.GetSelectedObjects(false, false))
{
    if (doc.Objects.Transform(obj.Id, xform, true) != Guid.Empty) scaled++;
}
doc.Views.Redraw();
return new { scaled = scaled, factor = 2.0 };
